#include <bits/stdc++.h>
using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<vector<long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0], v = e[1], s = e[2], end = e[3];
        adj[u].push_back({v, s, end});
    }

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        long long current_time = pq.top().first;
        long long u = pq.top().second;
        pq.pop();

        if (u == n - 1) {
            return current_time;
        }

        if (current_time > dist[u]) {
            continue;
        }

        for (auto& edge : adj[u]) {
            long long v = edge[0], s = edge[1], end = edge[2];
            long long earliest_time = max(s, current_time);
            if (earliest_time <= end) {
                long long new_time = earliest_time + 1;
                if (new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.push({new_time, v});
                }
            }
        }
    }

    return -1;
}

