    public static long solve(long n, long[][] edges) {
        List<List<int[]>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] e : edges) {
            long u = e[0], v = e[1], s = e[2], end = e[3];
            adj.get((int) u).add(new int[]{(int) v, (int) s, (int) end});
        }

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        long[] dist = new long[(int) n];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long current_time = current[0];
            long u = current[1];

            if (u == n - 1) {
                return current_time;
            }

            if (current_time > dist[(int) u]) {
                continue;
            }

            for (int[] edge : adj.get((int) u)) {
                long v = edge[0];
                long s = edge[1];
                long end = edge[2];
                long earliest = Math.max(current_time, s);
                if (earliest <= end) {
                    long new_time = earliest + 1;
                    if (new_time < dist[(int) v]) {
                        dist[(int) v] = new_time;
                        pq.offer(new long[]{new_time, (int) v});
                    }
                }
            }
        }

        return -1;
    }
}
